 36→type NavViewData =
 37→  | { type: 'grid' }
 38→  | { type: 'clipboard' }
 39→  | { type: 'snippets' }
 40→  | { type: 'emoji' }
 41→  | {
 42→      type: 'detail';
 43→      item: ListItemData;
 44→    };
