 46→function filterSections(sections: SectionData[], query: string): SectionData[] {
 47→  if (!query) return sections;
 48→  const lower = query.toLowerCase();
 49→  return sections
 50→    .map(section => ({
 51→      ...section,
 52→      items: section.items.filter(
 53→        item =>
 54→          item.title.toLowerCase().includes(lower) ||
 55→          item.subtitle?.toLowerCase().includes(lower),
 56→      ),
 57→    }))
 58→    .filter(section => section.items.length > 0);
 59→}
 60→
 61→function filterColors(colors: ColorItemData[], query: string): ColorItemData[] {
 62→  if (!query) return colors;
 63→  const lower = query.toLowerCase();
 64→  return colors.filter(
 65→    c =>
 66→      c.title.toLowerCase().includes(lower) ||
 67→      c.subtitle?.toLowerCase().includes(lower),
 68→  );
 69→}
 70→
 71→function flattenItems(sections: SectionData[]): ListItemData[] {
 72→  return sections.flatMap(s => s.items);
 73→}
 74→
 75→function renderMetadataEntry(entry: ListItemMetadataEntry, index: number) {
 76→  switch (entry.type) {
 77→    case 'label':
 78→      return (
 79→        <DetailMetadata.Label
 80→          key={index}
 81→          title={entry.title}
 82→          text={entry.text}
 83→        />
 84→      );
 85→    case 'link':
 86→      return (
 87→        <DetailMetadata.Link
 88→          key={index}
 89→          title={entry.title}
 90→          text={entry.text}
 91→          target={entry.target}
 92→        />
 93→      );
 94→    case 'tag-list':
 95→      return (
 96→        <DetailMetadata.TagList key={index} title={entry.title}>
 97→          {entry.tags.map(tag => (
 98→            <DetailMetadata.Tag
 99→              key={tag.text}
100→              text={tag.text}
101→              color={tag.color}
102→            />
103→          ))}
104→        </DetailMetadata.TagList>
105→      );
106→    case 'separator':
107→      return <DetailMetadata.Separator key={index} />;
108→  }
109→}
