179→interface ColorPickerViewProps {
180→  colors: ColorItemData[];
181→  onActiveIndexChange: (index: number) => void;
182→  onAction: (index: number) => void;
183→}
184→
185→function ColorPickerView({
186→  colors,
187→  onActiveIndexChange,
188→  onAction,
189→}: ColorPickerViewProps) {
190→  if (colors.length === 0) {
191→    return (
192→      <EmptyState
193→        icon={<SearchIcon />}
194→        title="No Colors"
195→        description="Try a different search term"
196→      />
197→    );
198→  }
199→
200→  return (
201→    <Grid
202→      itemCount={colors.length}
203→      columns={4}
204→      onActiveIndexChange={onActiveIndexChange}
205→      onAction={onAction}
206→    >
207→      {colors.map((color, index) => (
208→        <GridItem
209→          key={color.id}
210→          index={index}
211→          icon={<ColorSwatch color={color.color} />}
212→          title={color.title}
213→          subtitle={color.subtitle}
214→        />
215→      ))}
