226→      metadata={
227→        itemDetail.metadata ? (
228→          <DetailMetadata>
229→            {itemDetail.metadata.map(renderMetadataEntry)}
230→          </DetailMetadata>
231→        ) : undefined
232→      }
233→    />
234→  );
235→}
