280→    () => [
281→      {
282→        options: [
283→          {
284→            label: 'All Colors',
285→            value: 'all',
286→          },
287→        ],
288→      },
289→      {
290→        title: 'Category',
291→        options: [
292→          {
293→            label: 'Warm',
294→            value: 'warm',
295→          },
296→          {
297→            label: 'Cool',
298→            value: 'cool',
299→          },
300→          {
301→            label: 'Neutral',
302→            value: 'neutral',
303→          },
